INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Inline code suggestions$q$, $q$Real-time, context-aware code completions as you type, supporting many popular programming languages across supported IDEs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Conversational chat$q$, $q$An in-IDE chat interface for asking questions, debugging errors, and getting explanations of code or AWS services.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Automated code transformation$q$, $q$An agentic feature that performs large-scale code upgrades, most notably automated Java version migrations (e.g., Java 8/11 to 17).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Feature development agent$q$, $q$An agent that can plan and implement multi-file code changes from a natural-language task description.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Security vulnerability scanning$q$, $q$Scans code for common security issues and suggests remediations, building on AWS's static-analysis capabilities.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Unit test generation$q$, $q$Automatically generates unit tests for existing functions and code paths to improve coverage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Inline documentation generation$q$, $q$Generates code comments and documentation to help explain and maintain codebases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$AWS console assistance$q$, $q$Provides troubleshooting and operational guidance for deployed AWS infrastructure, not just source code.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Broad IDE and CLI support$q$, $q$Available as extensions for VS Code, JetBrains IDEs, Visual Studio, and the AWS command line, plus AWS Cloud9 and JupyterLab.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Enterprise administration via IAM Identity Center$q$, $q$Pro tier adds centralized identity, access policy, and usage management for organizations.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Deep, native understanding of AWS services, SDKs, and infrastructure patterns$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Powerful automated code transformation agent for large-scale Java version upgrades$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Broad IDE coverage including VS Code, JetBrains, Visual Studio, and the CLI$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Free tier available with no AWS Pro subscription required to get started$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Combines coding assistance with security scanning and AWS console troubleshooting in one product$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Most valuable to teams already using AWS; less compelling for multi-cloud or non-AWS stacks$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Pro tier setup requires configuring AWS IAM Identity Center, adding administrative overhead$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Free tier has usage limits on chat interactions and code suggestions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Feature depth for non-Java modernization/transformation use cases is comparatively newer$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Enterprise features and pricing are structured around AWS billing, which may not suit teams outside the AWS ecosystem$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Is Amazon Q Developer free to use?$q$, $q$Yes, Amazon Q Developer offers a free tier with code suggestions and a limited number of chat interactions. A paid Pro tier is available for higher usage limits and enterprise administration.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$What was Amazon Q Developer called before?$q$, $q$Amazon Q Developer evolved from Amazon CodeWhisperer, AWS's original AI code-completion assistant, and was rebranded and expanded under the Amazon Q product family in 2024.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Which IDEs does Amazon Q Developer support?$q$, $q$It's available in VS Code, JetBrains IDEs, Visual Studio, AWS Cloud9, JupyterLab, and the AWS command line, in addition to the AWS Management Console.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Can Amazon Q Developer upgrade legacy Java applications automatically?$q$, $q$Yes, its code transformation agent can automate upgrading Java applications, such as migrating from Java 8 or 11 to Java 17, reducing the manual effort typically required for these upgrades.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Do I need an AWS account to use Amazon Q Developer?$q$, $q$You need an AWS Builder ID for the free tier, or an AWS account with IAM Identity Center configured to use the Pro tier's enterprise features.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Everyday AI-assisted coding$q$, $q$Developers get inline code completions and chat-based help while writing application code in their IDE of choice.$q$, $q$Individual developers and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Large-scale Java version upgrades$q$, $q$Teams use the automated code transformation agent to modernize legacy Java applications to newer, supported runtime versions.$q$, $q$Enterprises with legacy Java codebases$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$AWS infrastructure troubleshooting$q$, $q$Engineers use Q Developer inside the AWS Management Console to diagnose and resolve issues with deployed cloud resources.$q$, $q$DevOps and cloud infrastructure teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Security and quality hardening$q$, $q$Teams run automated vulnerability scans and generate unit tests to improve code security and test coverage before release.$q$, $q$Security-conscious engineering and platform teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Free tier$q$, $q$$0$q$, NULL, $q$["Inline code suggestions","Limited chat interactions per month","Security scans (limited)","Available via AWS Builder ID sign-in"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$Pro tier$q$, $q$$19/user/month$q$, $q$monthly$q$, $q$["Higher usage limits for chat and code suggestions","Automated code transformation (e.g., Java upgrades)","Centralized administration via AWS IAM Identity Center","Enterprise usage policies and management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Amazon Q Developer is AWS's generative AI assistant for software development, built to help engineers write, understand, test, and modernize code without leaving their existing tools. It evolved out of Amazon CodeWhisperer, the company's original AI code-completion product, and was relaunched under the broader 'Amazon Q' brand in 2024 as Amazon expanded the assistant's scope beyond autocomplete into full agentic workflows.$q$, $q$The product plugs into everyday developer environments, including VS Code, the JetBrains family of IDEs, Visual Studio, the AWS command line, and the AWS Management Console itself, so suggestions and chat show up directly where code is written and AWS infrastructure is managed. Because it's built by AWS, Q Developer has particularly deep awareness of AWS services, SDKs, and best practices, which differentiates it from more general-purpose coding assistants.$q$, $q$Beyond inline code completion, Amazon Q Developer offers conversational chat for debugging and explaining code, automated unit test generation, security vulnerability scanning, and agentic 'transform' capabilities that can perform large-scale code upgrades, most notably automated Java version upgrades (for example, moving legacy Java 8 or 11 applications to Java 17).$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$who-its-for$q$, $q$Who Amazon Q Developer Is For$q$, 2, ARRAY[$q$Amazon Q Developer is best suited for teams and individual developers already working inside the AWS ecosystem. Engineers building on Lambda, EC2, ECS, or other AWS services benefit most from its context-aware suggestions, since the assistant is trained with deep familiarity of AWS APIs, IAM permissions, and infrastructure-as-code patterns that generic coding assistants may not handle as precisely.$q$, $q$It's also a strong fit for enterprises managing large, aging codebases, particularly Java shops that need to upgrade outdated runtime versions across many services. The automated code transformation agent is designed specifically to tackle the kind of tedious, high-risk modernization work that would otherwise consume weeks of manual developer effort.$q$, $q$Organizations already standardized on AWS IAM Identity Center for workforce identity will find the Pro tier's administration, policy controls, and usage analytics straightforward to adopt, making Q Developer a natural choice for platform and DevOps teams responsible for governance across many engineers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that are heavily invested in other cloud providers, such as Google Cloud or Azure, or that intentionally keep their stack cloud-agnostic, may not see the same advantage from Q Developer's AWS-centric training and integrations that they would from a more platform-neutral assistant.$q$, $q$Developers who want a single tool that combines general-purpose chat, image understanding, and broad multi-cloud reasoning in one lightweight package may find Q Developer's feature set narrower and more infrastructure-focused than alternatives built for general knowledge-work assistance.$q$, $q$Small teams or hobbyists who don't use AWS at all, and don't need enterprise identity management or large-scale code migration tooling, may find the setup (particularly configuring IAM Identity Center for the Pro tier) more overhead than it's worth compared to simpler, IDE-native assistants.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Amazon Q Developer's core capability is real-time, context-aware code suggestions as developers type, spanning many popular programming languages and IDEs. Alongside this sits a conversational chat interface for asking questions about code, debugging errors, and getting explanations of unfamiliar codebases or AWS services directly inside the editor.$q$, $q$Its agentic features go further than autocomplete: the /dev-style feature-implementation agent can plan and generate multi-file changes from a natural-language task description, while the code transformation agent automates complex, large-scale upgrades such as Java version migrations. Q Developer also includes automated unit test generation, inline documentation generation, and security scanning that flags vulnerabilities and suggests fixes, building on AWS's existing CodeGuru-style static analysis heritage.$q$, $q$For teams operating in the AWS console itself, Q Developer extends into infrastructure troubleshooting and operational assistance, helping diagnose issues across deployed AWS resources, not just source code, which sets it apart from IDE-only coding assistants.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', $q$the-experience$q$, $q$The Amazon Q Developer Experience$q$, 2, ARRAY[$q$Using Amazon Q Developer typically starts with installing the AWS Toolkit extension for your IDE of choice and signing in, either with a personal AWS Builder ID for the free tier or through AWS IAM Identity Center for the Pro tier. From there, suggestions appear inline as you type, and a chat panel is available for more involved questions or multi-step tasks.$q$, $q$Because it is deeply integrated with AWS, the day-to-day experience feels most seamless for developers who are already working with AWS services and want an assistant that understands their cloud context, not just their local code. The transformation and agentic features involve a more guided, review-based workflow, where the agent proposes a plan or diff for larger changes and the developer reviews and approves the result before it's merged.$q$, $q$Overall, the experience positions Amazon Q Developer less as a general chatbot bolted onto an editor and more as an AWS-native productivity layer across the software lifecycle, from writing and testing code to securing and modernizing it.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a22c6c2-59c3-4413-a1b0-00a743efb872', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
