INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('769d68c4-6d5c-4d50-b613-c3ab3a76591a', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Contact & Lead Management$q$, $q$Centralized database for contacts, accounts, and leads with activity tracking and custom fields.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Sales Pipeline & Opportunity Tracking$q$, $q$Visual, customizable sales pipelines for tracking deals from first contact through close.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Quotes & Invoicing$q$, $q$Create quotes, convert them to invoices, and track payments without leaving the CRM.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Project Management$q$, $q$Task lists, milestones, and timesheets for managing delivery work tied back to a customer or deal.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Helpdesk & Case Management$q$, $q$Ticket-based customer support app for logging and resolving customer issues.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Email Marketing$q$, $q$Built-in campaign tools for sending and tracking email marketing to contact lists.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Workflow Automation$q$, $q$Rule-based automation to move records between statuses and trigger notifications or tasks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Customization (Custom Fields & Layouts)$q$, $q$Extensive custom fields, page layouts, and app configuration without needing developer resources.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Mobile Apps$q$, $q$Native iOS and Android apps for managing contacts, deals, and tasks on the go.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Open API & Integrations$q$, $q$API access plus connectors to tools like Google Workspace, Microsoft 365, QuickBooks, and Slack.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Very low cost per user relative to the number of included apps and features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Genuinely free plan available for very small teams (up to 3 users)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Broad suite covering CRM, invoicing, projects, and support in one login$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Highly customizable fields, layouts, and workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Responsive customer support frequently praised in user reviews$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Interface feels dated compared to modern CRM competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Learning curve from the sheer number of apps and configuration options$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Interface is primarily English-only with limited localization$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Some advanced automation and AI capabilities lag behind specialized CRM vendors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Depth of individual modules (e.g., marketing, support) is generally lighter than dedicated point solutions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Does Apptivo have a free plan?$q$, $q$Yes. Apptivo offers a free plan for up to three users that includes core CRM apps and limited storage, making it accessible to very small teams or solo users before upgrading to a paid tier.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$What is included in Apptivo besides CRM?$q$, $q$Beyond CRM, Apptivo includes apps for invoicing and quotes, project management, timesheets, procurement, and a helpdesk/case management system, all sharing the same underlying customer and deal data.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Is Apptivo good for non-CRM use cases like invoicing or project management?$q$, $q$Apptivo is often chosen specifically because it bundles invoicing and project management with CRM, so businesses that need those functions alongside sales tracking can avoid paying for separate standalone tools.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$How does Apptivo's pricing compare to other CRMs?$q$, $q$Apptivo is generally positioned as one of the lower-cost options among full-featured CRM suites, with paid plans starting well below many competitors while still including a large number of connected apps.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Does Apptivo integrate with other business tools?$q$, $q$Apptivo offers an open API along with integrations for common tools such as Google Workspace, Microsoft 365, QuickBooks, and Slack, allowing it to connect with an existing software stack.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Small Service Business Operations$q$, $q$Track leads through the sales pipeline, send quotes, convert them to invoices, and manage delivery projects all in one connected system.$q$, $q$Consultancies, agencies, and field service businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Budget-Constrained Sales Teams$q$, $q$Run core CRM functions like contact management and pipeline tracking at low per-user cost, starting on the free tier.$q$, $q$Startups and solo entrepreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Unified Customer Support and Sales$q$, $q$Combine helpdesk ticketing with CRM records so support and sales teams see the same customer history.$q$, $q$Small businesses with combined sales and support teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Project-Based Client Delivery$q$, $q$Move a closed deal directly into a tracked project with tasks, milestones, and timesheets tied to the original customer record.$q$, $q$Project-based teams and professional services firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Starter (Free)$q$, $q$Free$q$, NULL, $q$["Up to 3 users","Core CRM apps","Limited document storage","Email and phone support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Lite$q$, $q$$15/user/month (billed annually); $20/user/month billed monthly$q$, $q$monthly$q$, $q$["~18 apps included","Lead and deal management","100 custom fields","1GB file storage per user"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Premium$q$, $q$$25/user/month (billed annually); $30/user/month billed monthly$q$, $q$monthly$q$, $q$["~46 apps included","Sales forecasting","250 custom fields","3GB file storage per user"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$Ultimate$q$, $q$$40/user/month (billed annually); $50/user/month billed monthly$q$, $q$monthly$q$, $q$["~57 apps included","Advanced automation and workflows","350 custom fields","10GB file storage per user"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Apptivo is a cloud-based business management platform built around a core CRM but extending into a wide catalog of connected apps covering sales, invoicing, project management, procurement, and customer support. Founded around 2009 and headquartered in Fremont, California, the company built its reputation by offering a large bundle of business software for a fraction of the cost of buying separate best-of-breed tools.$q$, $q$Rather than positioning itself as a single-purpose CRM competing head-on with Salesforce or HubSpot, Apptivo leans into breadth: dozens of interconnected apps (contacts, opportunities, invoices, projects, timesheets, purchase orders, and more) share the same data model, so a lead can flow from the CRM into a quote, an invoice, and a project without leaving the platform. This 'one login, many apps' approach is the core of its value proposition for cost-conscious small and mid-sized businesses.$q$, $q$Apptivo is delivered entirely through the browser with companion mobile apps, and it markets itself heavily on affordability and configurability rather than cutting-edge design or AI-first workflows, which shapes who gets the most value from it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$who-apptivo-is-for$q$, $q$Who Apptivo Is For$q$, 2, ARRAY[$q$Apptivo is best suited to small and mid-sized businesses that want CRM, invoicing, and project tracking under one roof instead of stitching together several separate subscriptions. Service businesses, consultancies, and field-based teams that quote work, track deals, and then bill and deliver on projects tend to get the most value from having all of that in a single connected system.$q$, $q$It also appeals strongly to budget-sensitive teams and solo operators, since the free tier and low per-user pricing on paid plans make it accessible for businesses that would otherwise be priced out of a full CRM-plus-operations stack. Teams that value deep configurability — custom fields, custom layouts, and workflow rules — over a polished out-of-the-box experience are a good fit, since Apptivo is generally more flexible to reshape than sleeker, more opinionated competitors.$q$, $q$Organizations already comfortable managing their own setup (rather than relying on a vendor-provided implementation team) will get the most out of the platform's app marketplace and customization options.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger enterprises with complex governance, security, or compliance requirements, or teams that need a highly polished, modern interface as a baseline expectation, are likely to be frustrated by Apptivo. Its UI is frequently described in reviews as functional but dated compared to newer CRMs, and the sheer number of apps and settings can create a steeper learning curve than a focused, single-purpose tool.$q$, $q$Teams whose priority is a best-in-class CRM experience specifically — deep native AI features, cutting-edge automation, or a large curated marketplace of third-party integrations — may be better served by more specialized platforms, since Apptivo's strength is breadth of connected business apps rather than depth of any one module.$q$, $q$Companies needing a fully localized interface for non-English-speaking staff should also look elsewhere, as Apptivo's interface is primarily English-only.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Apptivo offers standard CRM functionality: contact and account management, lead capture, a visual sales pipeline, opportunity tracking, and email integration. Layered on top are apps for creating quotes and invoices, tracking payments, and managing purchase orders, which let sales and finance activity live in the same system rather than a separate accounting tool.$q$, $q$Beyond sales, Apptivo includes project management (tasks, timesheets, milestones), a helpdesk/case management app for customer support tickets, and email marketing campaign tools. Workflow automation and a large number of customizable fields and layouts let teams adapt each app to their own processes without custom development.$q$, $q$The suite is rounded out by mobile apps for iOS and Android, an open API for integrations, and connectors to common third-party tools such as Google Workspace, Office 365, QuickBooks, and Slack, so the platform can slot into an existing tech stack rather than requiring a full replacement of it.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('943e842e-ea6b-423a-ad07-1657fff38f93', $q$the-apptivo-experience$q$, $q$The Apptivo Experience$q$, 2, ARRAY[$q$Day-to-day, Apptivo feels like a large, configurable toolbox rather than a single streamlined product. New users generally need some ramp-up time to understand which of the dozens of available apps they actually need and how they interconnect, and the interface, while functional, doesn't have the visual polish of newer CRM entrants.$q$, $q$Where Apptivo consistently earns praise in user reviews is value for money and customer support responsiveness — reviewers frequently note that the breadth of included apps and the ability to reach support directly makes the platform feel like strong value relative to its price, especially compared to paying for separate CRM, invoicing, and project tools individually.$q$, $q$Overall, the experience rewards teams willing to invest a bit of setup time to configure the apps they need, in exchange for an affordable, all-in-one back office that scales from a single free user up to larger paid teams without switching platforms.$q$]::text[], 4);
